class GANModel {
public:
    void generate(const float* z, int label, float* out);

private:
    float buf_a[128];
    float buf_b[128];
    float emb_buf[32];
};

void GANModel::generate(const float* z, int label, float* out) {
    // Conditional generation: embed the label and concatenate to z
    if (label < 0 || label >= 3) label = 0;
    for (int k = 0; k < 32; k++) {
        emb_buf[k] = label_embed[label][k];
    }
    // Concatenate z and embedding into buf_a
    for (int k = 0; k < 4; k++) buf_a[k] = z[k];
    for (int k = 0; k < 32; k++) buf_a[4 + k] = emb_buf[k];
    float* src = buf_a;
    float* dst = buf_b;

    // Block 0: linear 36→128  act=relu  bn=True  cond=True
    for (int k = 0; k < 128; k++) {
        float acc = gen0_b[k];
        for (int j = 0; j < 36; j++)
            acc += gen0_W[k][j] * src[j];
        float rmean = gen0_bn_rmean[k];
        float rvar  = gen0_bn_rvar[k];
        // Conditional BN: compute gamma and beta from label embedding
        float gamma = gen0_bn_gamma_b[k];
        for (int j = 0; j < 32; j++) {
            gamma += gen0_bn_gamma_w[k][j] * emb_buf[j];
        }
        float beta = gen0_bn_beta_b[k];
        for (int j = 0; j < 32; j++) {
            beta += gen0_bn_beta_w[k][j] * emb_buf[j];
        }
        acc = gamma * (acc - rmean) / sqrtf(rvar + 1e-5f) + beta;
        if (acc < 0.0f) acc = 0.0f;
        dst[k] = acc;
    }
    { float* tmp = src; src = dst; dst = tmp; }

    // Block 1: linear 128→128  act=relu  bn=True  cond=True
    for (int k = 0; k < 128; k++) {
        float acc = gen1_b[k];
        for (int j = 0; j < 128; j++)
            acc += gen1_W[k][j] * src[j];
        float rmean = gen1_bn_rmean[k];
        float rvar  = gen1_bn_rvar[k];
        // Conditional BN: compute gamma and beta from label embedding
        float gamma = gen1_bn_gamma_b[k];
        for (int j = 0; j < 32; j++) {
            gamma += gen1_bn_gamma_w[k][j] * emb_buf[j];
        }
        float beta = gen1_bn_beta_b[k];
        for (int j = 0; j < 32; j++) {
            beta += gen1_bn_beta_w[k][j] * emb_buf[j];
        }
        acc = gamma * (acc - rmean) / sqrtf(rvar + 1e-5f) + beta;
        if (acc < 0.0f) acc = 0.0f;
        dst[k] = acc;
    }
    { float* tmp = src; src = dst; dst = tmp; }

    // Block 2: linear 128→2  act=linear  bn=False  cond=True
    for (int k = 0; k < 2; k++) {
        float acc = gen2_b[k];
        for (int j = 0; j < 128; j++)
            acc += gen2_W[k][j] * src[j];
        out[k] = acc;
    }
}